 题意
给定一个  nnn 和 aia_iai​ 和 vvv。有 mmm 次操作，每次等概率选择 i∈[1,n]i\in [1,n]i∈[1,n]，将 ∀j∈[i,n],aj←aj+v\forall j\in [i,n],a_j\leftarrow a_j+v∀j∈[i,n],aj​←aj​+v，求操作结束后 ∏ai\prod a_i∏ai​ 期望。
n≤5000n\leq 5000n≤5000，m,v,ai≤109m,v,a_i\leq 10^9m,v,ai​≤109
 做法
考虑组合意义，∏ai\prod a_i∏ai​ 相当于一个人从 iii 走向 i+1i+1i+1 有 vvv 种方案。那么加法操作就相当于我们可以在 ppp 后每次多有 vvv 条方案可以走。那么我们考虑动态规划，设 fi,jf_{i,j}fi,j​ 表示前 iii 个位置，已经用了  jjj 个操作的方案数。那么有转移：
fi,jai+1→fi+1,jf_{i,j}a_{i+1}\rightarrow f_{i+1,j}
fi,j​ai+1​→fi+1,j​
表示不用操作，
fi,jjv→fi+1,jf_{i,j}jv\rightarrow f_{i+1,j}
fi,j​jv→fi+1,j​
表示用原来的操作，
fi,j(i+1)(m−j)v→fi,j+1f_{i,j}(i+1)(m-j)v\rightarrow f_{i,j+1 }
fi,j​(i+1)(m−j)v→fi,j+1​
表示从旧的位置选择一个位置，填入 m−jm-jm−j 即一个还没有使用过的工具，那么答案就是：
∑fn,inm−inm\frac{\sum f_{n,i}n^{m-i}}{n^m}
nm∑fn,i​nm−i​
即表示剩下的 m−im-im−i 个操作不重要可以在 nnn 个位置中随便填。复杂度 O(n⋅min⁡(n,m))O(n\cdot\min(n,m))O(n⋅min(n,m))。
#include &lt;bits/stdc++.h&gt;#define rep(i,a,b) for(int i=(a);i&lt;=(b);++i)using namespace std;typedef long long ll;const int MAXN=5005;const int MOD=1e9+7;int ksm(int a,int b)&#123;    int ans=1;    while(b)&#123;        if(b&amp;1)&#123;            ans=1ll*ans*a%MOD;        &#125;        a=1ll*a*a%MOD;        b&gt;&gt;=1;    &#125;    return ans;&#125;int n,m,v,a[MAXN],f[MAXN][MAXN];#define add(x,y) (((x)+=(y))&gt;=MOD&amp;&amp;((x)-=MOD));int main()&#123;    ios::sync_with_stdio(false);    cin.tie(0);cout.tie(0);    cin&gt;&gt;n&gt;&gt;m&gt;&gt;v;    rep(i,1,n)&#123;        cin&gt;&gt;a[i];    &#125;    f[0][0]=1;    rep(i,0,n-1)&#123;        rep(j,0,min(m,i))&#123;            add(f[i+1][j],1ll*f[i][j]*a[i+1]%MOD);            add(f[i+1][j],1ll*f[i][j]*j%MOD*v%MOD);            add(f[i+1][j+1],1ll*f[i][j]*(i+1)%MOD*(m-j)%MOD*v%MOD);        &#125;    &#125;    int ans=0;    rep(i,0,min(n,m))&#123;        add(ans,1ll*f[n][i]*ksm(n,m-i)%MOD);    &#125;    ans=1ll*ans*ksm(ksm(n,m),MOD-2)%MOD;    cout&lt;&lt;ans&lt;&lt;&quot;\n&quot;;    return 0;&#125;

 题意
∑i=1n(ni)ik\sum_{i=1}^n\binom{n}{i}i^k
i=1∑n​(in​)ik
n≤109,k≤5000n\le 10^9,k\le 5000n≤109,k≤5000
 思路
∑i=0n(ni)ik\sum_{i=0}^n\binom{n}{i}i^k
i=0∑n​(in​)ik
∑i=0n(ni)∑j=1k{kj}ij‾\sum_{i=0}^n\binom{n}{i}\sum_{j=1}^k \begin{Bmatrix}k\\j\\\end{Bmatrix}i^{\underline{j}}
i=0∑n​(in​)j=1∑k​{kj​}ij​
∑j=1k{kj}∑i=0n(ni)ij‾\sum_{j=1}^k \begin{Bmatrix}k\\j\\\end{Bmatrix}\sum_{i=0}^n\binom{n}{i}i^{\underline{j}}
j=1∑k​{kj​}i=0∑n​(in​)ij​
∑j=1k{kj}j!∑i=0n(ni)(ij)\sum_{j=1}^k \begin{Bmatrix}k\\j\\\end{Bmatrix}j!\sum_{i=0}^n \binom{n}{i}\binom{i}{j}
j=1∑k​{kj​}j!i=0∑n​(in​)(ji​)
∑j=1k{kj}j!(nj)∑i=0n(n−ji−j)\sum_{j=1}^k \begin{Bmatrix}k\\j\\\end{Bmatrix}j!\binom{n}{j}\sum_{i=0}^n \binom{n-j}{i-j}
j=1∑k​{kj​}j!(jn​)i=0∑n​(i−jn−j​)
∑j=1k{kj}j!(nj)∑i=0n−j(n−ji)\sum_{j=1}^k \begin{Bmatrix}k\\j\\\end{Bmatrix}j!\binom{n}{j}\sum_{i=0}^{n-j}\binom{n-j}{i}
j=1∑k​{kj​}j!(jn​)i=0∑n−j​(in−j​)
