j=1∑k​{kj​}j!(jn​)2n−j

 题意
NNN 天，每天需要 rir_iri​ 个餐巾，用完后变成脏的。可以花费 ppp 买一条，或者花费 fff 在 mmm 天后获得一条，或者花费 sss 在 nnn 天后花费一条，或者留着，求最小花费。
 思路
考虑网络流。我们可以将一天拆为两个点，分别为早上和晚上，这样我们就可以区分出哪个点需要送出和哪个点可以存起来了。那么将早上和 TTT 连一个 (ri,0)(r_i,0)(ri​,0) 代表需要贡献出这么多脏的，然后因为这个会消失吗，所以再连 SSS 和晚上 (ri,0)(r_i,0)(ri​,0) 表示收到这么多脏的。那么留到第二天晚上就连 (inf⁡,0)(\inf,0)(inf,0)，两个花费就对应从晚上连到早上即可。
#include &lt;bits/stdc++.h&gt;#define rep(i,a,b) for(int i=(a);i&lt;=(b);++i)using namespace std;typedef long long ll;const int MAXN=4e3+5;const ll INFLL=1e17;const int INF=2e9;struct node&#123;    int v,w,nxt;    ll c;&#125;e[MAXN*20];int head[MAXN],tot=1;void add_one(int u,int v,int w,int c)&#123;    e[++tot]=&#123;v,w,head[u],c&#125;;    head[u]=tot;&#125;void add(int u,int v,int w,int c)&#123;    add_one(u,v,w,c);    add_one(v,u,0,-c);&#125;int S,T,arc[MAXN];ll dep[MAXN];bool vs[MAXN],inq[MAXN];bool spfa()&#123;    rep(i,S,T)&#123;        dep[i]=INFLL;        arc[i]=head[i];        inq[i]=false;    &#125;    queue&lt;int&gt;que;    que.push(S);    dep[S]=0;    while(!que.empty())&#123;        int u=que.front();        que.pop();        inq[u]=false;        for(int i=head[u];i;i=e[i].nxt)&#123;            int v=e[i].v;            if(e[i].w&amp;&amp;dep[u]+e[i].c&lt;dep[v])&#123;                dep[v]=dep[u]+e[i].c;                if(!inq[v])&#123;                    que.push(v);                &#125;            &#125;        &#125;    &#125;    return dep[T]!=INFLL;&#125;ll cost;int dfs(int u,int inflow)&#123;    if(u==T)&#123;        return inflow;    &#125;    vs[u]=true;    int outflow=0;    for(int i=arc[u];i;i=e[i].nxt)&#123;        arc[u]=i;        if(dep[u]+e[i].c!=dep[e[i].v]||!e[i].w||vs[e[i].v])&#123;            continue;        &#125;        int nf=dfs(e[i].v,min(inflow,e[i].w));        e[i].w-=nf;        e[i^1].w+=nf;        cost+=e[i].c*nf;        outflow+=nf;        inflow-=nf;        if(!inflow)&#123;            break;        &#125;    &#125;    vs[u]=false;    return outflow;&#125;int dinic()&#123;    int ans=0;    while(spfa())&#123;        ans+=dfs(S,INF);    &#125;    return ans;&#125;int main()&#123;    ios::sync_with_stdio(false);    cin.tie(0);cout.tie(0);    int N;    cin&gt;&gt;N;    S=0,T=2*N+1;    rep(i,1,N)&#123;        int r;        cin&gt;&gt;r;        add(i,T,r,0);        add(S,N+i,r,0);    &#125;    int p,m,f,n,s;    cin&gt;&gt;p&gt;&gt;m&gt;&gt;f&gt;&gt;n&gt;&gt;s;    rep(i,1,N)&#123;        if(i&lt;N)&#123;            add(N+i,N+i+1,INF,0);        &#125;        if(i+m&lt;=N)&#123;            add(N+i,i+m,INF,f);        &#125;        if(i+n&lt;=N)&#123;            add(N+i,i+n,INF,s);        &#125;        add(S,i,INF,p);    &#125;    int flw=dinic();    cout&lt;&lt;cost&lt;&lt;&quot;\n&quot;;    return 0;&#125;

 题意
给定 nnn 个红绿灯，其中周期，rir_iri​ 秒红，gig_igi​ 秒绿。随机一个数从 2019!2019!2019! 中开始从 000 开始向右走，问第 iii 个灯会停下的概率和全通过的概率。
n≤500,x≤105，r+g≤100n\leq 500,x\leq 10^5，r+g\leq 100n≤500,x≤105，r+g≤100
 思路
发现直接枚举循环节和位置判断合法，时间复杂度 O(n⋅lcm(ri+gi))O(n\cdot\mathrm{lcm}(r_i+g_i))O(n⋅lcm(ri​+gi​))。我们考虑周期的性质，发现对于一个 ri+gi⊥rj+gjr_i+g_i\perp r_j+g_jri​+gi​⊥rj​+gj​，那么它们的循环节一定不会重复，我们可以直接枚举每一个然后将它们的结果乘起来。那么对于 ri+gi∣rj+gjr_i+g_i|r_j+g_jri​+gi​∣rj​+gj​，则我们发现可以直接将其补全，这样对 lcm\mathrm{lcm}lcm 的大小不会有办法。我们可以枚举一个周期 TTT，然后对于每一个 TTT 里的大小去考虑，那么 ri+gi→gcd⁡(ri+gi,T)r_i+g_i\rightarrow \gcd(r_i+g_i,T)ri​+gi​→gcd(ri​+gi​,T)，时间复杂度 O(Tnmax⁡((ri+gi)′))O(Tn\max((r_i+g_i)^{&#x27;}))O(Tnmax((ri​+gi​)′))。我们首先需要利用互质的性质，发现 r+gr+gr+g 很小，那么我们可以考虑将 101010 以内的所有质数加进 TTT 里，即 26+34+52+72=63504002^6+3^4+5^2+7^2=635040026+34+52+72=6350400，这样所有的数都互质了。但是这样发现时间还是爆炸，但是发现我们还可以利用那个倍数，将 635400635400635400 开根号变为 252025202520。这样子的话我们就可以将 2,42,42,4 置为 888，将 333 置为 999，那么复杂度就不会变化了。
#include &lt;bits/stdc++.h&gt;#define rep(i,a,b) for(int i=(a);i&lt;=(b);++i)using namespace std;typedef long long ll;const int MAXN=505;const int MAXW=105;const int T=2520;int n,x[MAXN],w[MAXN],r[MAXN],g[MAXN];double ans[MAXN];bool vs[MAXN][MAXW],fw[MAXW][MAXW];void Do(int v)&#123;    memset(fw,false,sizeof fw);    double val=1;    ans[0]++;    rep(i,1,n)&#123;        int fm=0,fz=0;        rep(j,0,r[i]-1)&#123;            if(!fw[r[i]][j])&#123;                fm++;                if(vs[i][(v+j%g[i]*T)%w[i]])&#123;                    fz++;                &#125;else&#123;                    fw[r[i]][j]=true;                &#125;            &#125;        &#125;        if(!fz)&#123;            break;        &#125;        val*=fz*1.0/fm;        ans[i]+=val;    &#125;&#125;int main()&#123;    ios::sync_with_stdio(false);    cin.tie(0);cout.tie(0);    cin&gt;&gt;n;    rep(i,1,n)&#123;        cin&gt;&gt;x[i]&gt;&gt;r[i]&gt;&gt;g[i];        w[i]=r[i]+g[i];        x[i]%=w[i];        rep(j,r[i],w[i]-1)&#123;            vs[i][(j-x[i]+w[i])%w[i]]=true;        &#125;    &#125;    rep(i,1,n)&#123;        r[i]=g[i]=w[i]/__gcd(w[i],T);        if(g[i]==2||g[i]==4)&#123;            r[i]=8;        &#125;else if(g[i]==3)&#123;            r[i]=9;        &#125;    &#125;    rep(i,0,T-1)&#123;        Do(i);    &#125;    rep(i,0,n)&#123;        ans[i]/=T;    &#125;    rep(i,1,n+1)&#123;        cout&lt;&lt;fixed&lt;&lt;setprecision(10)&lt;&lt;ans[i-1]-ans[i]&lt;&lt;&quot;\n&quot;;    &#125;    return 0;&#125;

 题意
(∑k=0nf(k)×xk×(nk)) mod p\left(\sum_{k=0}^{n}f(k)\times x^k\times \binom{n}{k}\right)\bmod p
(k=0∑n​f(k)×xk×(kn​))modp
f(k)f(k)f(k) 为给定的一个 mmm 次多项式。
n,x,p≤109,m≤1000n,x,p\le 10^9,m\le 1000n,x,p≤109,m≤1000
 思路
对于下降幂有性质：
(nk)km‾=(n−mk−m)nm‾\binom{n}{k}k^{\underline{m}}=\binom{n-m}{k-m}n^{\underline{m}}
(kn​)km​=(k−mn−m​)nm​

证明：
(nk)km‾=n!k!(n−k)!k!(k−m)!\binom{n}{k}k^{\underline{m}}=\frac{n!}{k!(n-k)!}\frac{k!}{(k-m)!}
(kn​)km​=k!(n−k)!n!​(k−m)!k!​
=n!(n−k)!(k−m)!=\frac{n!}{(n-k)!(k-m)!}
=(n−k)!(k−m)!n!​
=n!(n−m)!(n−k)!(k−m)!(n−m)!=\frac{n!(n-m)!}{(n-k)!(k-m)!(n-m)!}
=(n−k)!(k−m)!(n−m)!n!(n−m)!​
=(n−m)!(n−m−(k−m))!(k−m)!n!(n−m)!=\frac{(n-m)!}{(n-m-(k-m))!(k-m)!}\frac{n!}{(n-m)!}
=(n−m−(k−m))!(k−m)!(n−m)!​(n−m)!n!​
=(n−mk−m)nm‾=\binom{n-m}{k-m}n^{\underline{m}}
=(k−mn−m​)nm​

那么考虑将题目所给多项式 f(k)=∑iaixif(k)=\sum_i a_ix^if(k)=∑i​ai​xi 先转成下降幂形式的 f(k)=∑i=0mbiki‾f(k)=\sum_{i=0}^m b_ik^{\underline{i}}f(k)=∑i=0m​bi​ki​。
∑k=0n∑i=0mbiki‾×xk×(nk)\sum_{k=0}^{n}\sum_{i=0}^mb_ik^{\underline{i}}\times x^k\times \binom{n}{k}
k=0∑n​i=0∑m​bi​ki​×xk×(kn​)
=∑i=0mbini‾∑k=0n(n−ik−i)xk=\sum_{i=0}^mb_in^{\underline{i}}\sum_{k=0}^n\binom{n-i}{k-i}x^k
=i=0∑m​bi​ni​k=0∑n​(k−in−i​)xk
=∑i=0mbini‾xi∑k=0n−i(n−ik)xk=\sum_{i=0}^mb_in^{\underline{i}}x^i\sum_{k=0}^{n-i}\binom{n-i}{k}x^k
=i=0∑m​bi​ni​xik=0∑n−i​(kn−i​)xk
=∑i=0mbini‾xi(x+1)n−i=\sum_{i=0}^mb_in^{\underline{i}}x^i(x+1)^{n-i}
=i=0∑m​bi​ni​xi(x+1)n−i
又因为
xn=∑i=0n{ni}xi‾x^n=\sum_{i=0}^n \begin{Bmatrix}  n  \\ i \\\end{Bmatrix}x^{\underline{i}}
xn=i=0∑n​{ni​}xi​
带入得
∑i=0maixi=∑i=0m∑j=0iai{ij}xj‾\sum_{i=0}^ma_ix^i=\sum_{i=0}^m\sum_{j=0}^i a_i\begin{Bmatrix} i \\ j \\\end{Bmatrix}x^{\underline{j}}
i=0∑m​ai​xi=i=0∑m​j=0∑i​ai​{ij​}xj​
=∑j=0m(∑i=jmai{ij})xj‾=\sum_{j=0}^m\left(\sum_{i=j}^ma_i\begin{Bmatrix} i \\ j \\\end{Bmatrix}\right)x^{\underline{j}}
=j=0∑m​(i=j∑m​ai​{ij​})xj​
即
bi=∑j=imaj{ji}b_i=\sum_{j=i}^ma_j\begin{Bmatrix} j \\ i \\\end{Bmatrix}
bi​=j=i∑m​aj​{ji​}

 题意
给出一张图，求每个点开始每一次走编号最小另一个点没有加入的边的边的编号拼起来的数字。
n≤2⋅105n\leq 2\cdot 10^5n≤2⋅105
 思路
我们考虑最小生成树，那么考虑一条边的一个节点，那么一定是先走完它的已经经过的集合再走这条边再走另一个点的集合。那么我们可以用 Kruskal 重构树去维护，等价于区间乘和加。但是我们发现，我们可以直接在并查集上打区间乘和加的标记，因为是支持路径压缩的。
#include &lt;bits/stdc++.h&gt;#define rep(i,a,b) for(int i=(a);i&lt;=(b);++i)using namespace std;typedef long long ll;const int MAXN=2e5+5;const int MOD=1e9+7;int n,m,f[MAXN*2];pair&lt;int,int&gt;ans[MAXN*2];pair&lt;int,int&gt;merge(pair&lt;int,int&gt;x,pair&lt;int,int&gt;y)&#123;    return &#123;1ll*x.first*y.first%MOD,(1ll*x.second*y.first%MOD+y.second)%MOD&#125;;&#125;int find(int u)&#123;    if(u==f[u])&#123;        return u;    &#125;    int fa=find(f[u]);    ans[u]=merge(ans[u],ans[f[u]]);    f[u]=fa;    // cout&lt;&lt;u&lt;&lt;&quot; &quot;&lt;&lt;fa&lt;&lt;&quot; &quot;&lt;&lt;ans[u].second&lt;&lt;&quot; &quot;&lt;&lt;ans[fa].second&lt;&lt;&quot;\n&quot;;    return fa;&#125;int main()&#123;    ios::sync_with_stdio(false);    cin.tie(0);cout.tie(0);    cin&gt;&gt;n&gt;&gt;m;    rep(i,1,2*n)&#123;        f[i]=i;        ans[i]=&#123;1,0&#125;;    &#125;    int tot=n;    rep(i,1,m)&#123;        int x,y;        cin&gt;&gt;x&gt;&gt;y;        int rx=find(x),ry=find(y);        if(rx==ry)&#123;            continue;        &#125;        pair&lt;int,int&gt;vx=ans[x],vy=ans[y];        ans[rx]=merge(&#123;10,i&#125;,vy);        ans[ry]=merge(&#123;10,i&#125;,vx);        // cout&lt;&lt;x&lt;&lt;&quot; &quot;&lt;&lt;y&lt;&lt;&quot; &quot;&lt;&lt;ans[rx].second&lt;&lt;&quot; &quot;&lt;&lt;ans[ry].second&lt;&lt;&quot; &quot;&lt;&lt;rx&lt;&lt;&quot; &quot;&lt;&lt;ry&lt;&lt;&quot;\n&quot;;        f[rx]=f[ry]=++tot;    &#125;    rep(i,1,n)&#123;        find(i);        cout&lt;&lt;ans[i].second&lt;&lt;&quot;\n&quot;;    &#125;    return 0;&#125;
